+import { isRelation } from '../../relation/utils/is-relation';
+import type { Trait } from '../../trait/types';
+import { createModifier } from '../modifier';
+import type { Predicate, PredicateValues } from '../types';
+
+let predicateId = 0;
+
+/**
+ * Creates a value-based query predicate. Dependencies must be data traits; tags and
+ * relations have no single value to provide to the predicate.
+ */
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    predicate: (values: PredicateValues<T>) => boolean
+): Predicate<T> {
+    for (const trait of traits) {
+        if (isRelation(trait) || trait[$internal].type === 'tag') {
+            throw new Error('Predicate dependencies must be data traits, not tags or relations.');
+        }
+    }
+
+    const modifier = createModifier('predicate', predicateId++, traits) as Predicate<T>;
+    modifier.predicate = predicate;
+    return modifier;
+}
