+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { hasTrait } from '../../trait/trait';
+import type { Predicate, QueryInstance } from '../types';
+import type { World } from '../../world';
+
+export function matchesPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    const eid = getEntityId(entity);
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        const instance = world[$internal].traitInstances[trait.id]!;
+        values.push(trait[$internal].get(eid, instance.store));
+    }
+    return predicate.predicate(values as never);
+}
+
+export function checkPredicates(world: World, query: QueryInstance, entity: Entity): boolean {
+    const predicates = query.predicates;
+    for (const predicate of predicates.required) {
+        if (!matchesPredicate(world, entity, predicate)) return false;
+    }
+    for (const predicate of predicates.forbidden) {
+        if (matchesPredicate(world, entity, predicate)) return false;
+    }
+    if (predicates.or.length) {
+        for (const predicate of predicates.or) {
+            if (matchesPredicate(world, entity, predicate)) return true;
+        }
+        return false;
+    }
+    return true;
+}
